[package]
name = "os"
version = "0.1.0"
authors = ["Yifan Wu <shinbokuow@163.com>"]
edition = "2021"

# See more keys and their definitions at https://doc.rust-lang.org/cargo/reference/manifest.html

[dependencies]
lazy_static = { version = "1.4.0", features = ["spin_no_std"] }
log = "0.4"
bitflags = "1.2.1"
xmas-elf = "0.7.0"
# old version: virtio-drivers = { git = "https://github.com/rcore-os/virtio-drivers", rev = "4ee80e5" }
# virtio-drivers = { git = "https://github.com/rcore-os/virtio-drivers", rev = "61ece50" }
virtio-drivers = "0.6.0"
spin = "0.10"
bit_field = "0.10.1"
#ext4_rs = { path = "libs/ext4_rs" }
lwext4_rust= { path = "./libs/lwext4_rsut"}
hashbrown = "0.12.0"
num_enum = { version = "0.7.2", default-features = false }
buddy_system_allocator = "0.11.0"
smoltcp = { path = "./libs/smoltcp", default-features = false, features = ["alloc", "log", "medium-ethernet", "medium-ip", "proto-ipv4", "socket-raw", "socket-icmp", "socket-udp", "socket-tcp", "socket-dns", "proto-igmp"] }


[target.'cfg(target_arch = "riscv64")'.dependencies]
riscv = { version = "0.11.1" }

[target.'cfg(target_arch = "loongarch64")'.dependencies]
loongarch64 = { version = "0.2.4", package = "loongArch64" }



[profile.dev]
debug = true

[profile.release]
debug = true

use std::{env, io::Result};

fn main() -> Result<()> {
    gen_linker_script()
}

fn gen_linker_script() -> Result<()> {
    let target_arch = env::var("CARGO_CFG_TARGET_ARCH").expect("can't find target");
    let fname = format!("linker_{}.lds", target_arch);
    let (output_arch, kernel_base) = if target_arch.contains("riscv64") {
        ("riscv", "0x80200000") // OpenSBI
    } else if target_arch.contains("loongarch64") {
        ("loongarch64", "0x82000000")
    } else {
        (target_arch.as_str(), "0")
    };
    let ld_content = std::fs::read_to_string("linker.lds")?;
    let ld_content = ld_content.replace("%ARCH%", output_arch);
    let ld_content = ld_content.replace("%KERNEL_BASE%", kernel_base);

    std::fs::write(&fname, ld_content)?;
    println!("cargo:rustc-link-arg=-T{}", fname);
    println!("cargo:rerun-if-env-changed=CARGO_CFG_KERNEL_BASE");
    println!("cargo:rerun-if-changed=build.rs");
    println!("cargo:rerun-if-changed=linker.lds");
    Ok(())
}

//! The main module and entrypoint
//!
//! Various facilities of the kernels are implemented as submodules. The most
//! important ones are:
//!
//! - [`trap`]: Handles all cases of switching from userspace to the kernel
//! - [`task`]: Task management
//! - [`syscall`]: System call handling and implementation
//! - [`mm`]: Address map using SV39
//! - [`sync`]: Wrap a static data structure inside it so that we are able to access it without any `unsafe`.
//! - [`fs`]: Separate user from file system with some structures
//!
//! The operating system also starts in this module. Kernel code starts
//! executing from `entry.asm`, after which [`rust_main()`] is called to
//! initialize various pieces of functionality. (See its source code for
//! details.)
//!
//! We then call [`task::run_tasks()`] and for the first time go to
//! userspace.

#![allow(missing_docs)]
#![no_std]
#![no_main]
#![feature(alloc_error_handler)]
#![allow(unused_imports)]
#![allow(dead_code)]
#![feature(naked_functions)]

#[macro_use]
extern crate log;

extern crate alloc;

#[macro_use]
extern crate bitflags;

#[path = "boards/qemu.rs"]
mod board;

#[macro_use]
pub mod config;
pub mod boot; // used to set up the initial environment
pub mod drivers;
pub mod fs;
pub mod hal;
pub mod lang_items;
pub mod logging;
pub mod mm;
pub mod net;
pub mod signal;
pub mod sync;
pub mod syscall;
pub mod task;
pub mod timer;
pub mod utils;

#[cfg(target_arch = "loongarch64")]
use crate::{
    hal::arch::info::{kernel_layout, print_machine_info},
    hal::trap::{enable_timer_interrupt, init},
    task::add_initproc,
};
pub mod system;
pub mod users;

use crate::hal::utils::console::CONSOLE;
use config::FLAG;
use core::arch::global_asm;

pub fn clear_bss() {
    extern "C" {
        fn sbss();
        fn ebss();
    }
    unsafe {
        core::slice::from_raw_parts_mut(
            sbss as usize as *mut u128,
            (ebss as usize - sbss as usize) / core::mem::size_of::<u128>(),
        )
        .fill(0);

